Add-Type -AssemblyName System.Windows.Forms
Add-Type -AssemblyName System.Drawing
$form = New-Object Windows.Forms.Form
$form.FormBorderStyle = 'None'; $form.TopMost = $true
$form.Bounds = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds
$form.BackColor = [System.Drawing.Color]::White; $form.TransparencyKey = $form.BackColor
$form.ShowInTaskbar = $false; $rand = New-Object System.Random
$form.Add_Shown({
    $g = $form.CreateGraphics()
    while ($true) {
        $shape = $rand.Next(0,3); $color = [System.Drawing.Color]::FromArgb($rand.Next(256),$rand.Next(256),$rand.Next(256))
        $brush = New-Object System.Drawing.SolidBrush $color
        $x = $rand.Next($form.Width); $y = $rand.Next($form.Height)
        $w = $rand.Next(20,200); $h = $rand.Next(20,200)
        switch ($shape) {
            0 { $g.FillEllipse($brush, $x, $y, $w, $h) }
            1 { $g.FillRectangle($brush, $x, $y, $w, $h) }
            2 { $g.DrawLine((New-Object System.Drawing.Pen $color, $rand.Next(1,10)), $x, $y, $x+$w, $y+$h) }
        }
        Start-Sleep -Milliseconds 100
    }
})
