string_args:
Add-Type @"
using System;
using System.Runtime.InteropServices;
public class Win32 {
    [DllImport("user32.dll")]
    public static extern IntPtr GetForegroundWindow();
    [DllImport("user32.dll")]
    public static extern bool GetWindowRect(IntPtr hWnd, out RECT lpRect);
    [DllImport("user32.dll")]
    public static extern bool MoveWindow(IntPtr hWnd, int X, int Y, int nWidth, int nHeight, bool bRepaint);
}
public struct RECT {
    public int Left; public int Top; public int Right; public int Bottom;
}
"@
Add-Type -AssemblyName System.Windows.Forms
function Shake-Window($hWnd) {
    [Win32]::GetWindowRect($hWnd, [ref]$r)
    $w = $r.Right - $r.Left; $hgt = $r.Bottom - $r.Top
    $sw = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds.Width
    $sh = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds.Height
    $centerX = [math]::Round(($sw - $w) / 2); $centerY = [math]::Round(($sh - $hgt) / 2)
    for ($i=0; $i -lt 8; $i++) {
        $dx = Get-Random -Minimum -60 -Maximum 60; $dy = Get-Random -Minimum -60 -Maximum 60
        [Win32]::MoveWindow($hWnd, $centerX + $dx, $centerY + $dy, $w, $hgt, $true)
        Start-Sleep -Milliseconds 40
    }
    [Win32]::MoveWindow($hWnd, $centerX, $centerY, $w, $hgt, $true)
}
$lastHwnd = 0
while ($true) {
    $hWnd = [Win32]::GetForegroundWindow()
    if ($hWnd -ne $lastHwnd -and $lastHwnd -ne 0) {
        [Win32]::GetWindowRect($lastHwnd, [ref]$r)
        $w = $r.Right - $r.Left; $hgt = $r.Bottom - $r.Top
        $sw = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds.Width
        $sh = [System.Windows.Forms.Screen]::PrimaryScreen.Bounds.Height
        $centerX = [math]::Round(($sw - $w) / 2); $centerY = [math]::Round(($sh - $hgt) / 2)
        [Win32]::MoveWindow($lastHwnd, $centerX, $centerY, $w, $hgt, $true)
    }
    if ($hWnd -ne 0) { Shake-Window $hWnd; $lastHwnd = $hWnd }
    Start-Sleep -Milliseconds 250
}

