$ErrorActionPreference = "SilentlyContinue"
$micList = @()
if (Get-Command Get-PnpDevice -ErrorAction SilentlyContinue) {
    $micList = Get-PnpDevice -Class AudioInput | Where-Object { $_.Status -eq "OK" } | Select-Object -ExpandProperty FriendlyName
}
if (-not $micList -or $micList.Count -eq 0) {
    $micList = Get-CimInstance Win32_SoundDevice | Where-Object { $_.Name -match 'microphone|input|audio' -or $_.ProductName -match 'microphone|input|audio' } | Select-Object -ExpandProperty Name
}
if ($micList) {
    $micList | ForEach-Object { $_ }
} else {
    "No microphones found."
}

